1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_PERCENT = 10;
3	const PERCENT_BASE = 100;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	};
12	
13	interface Item {
14	  type: string;
15	}
16	
17	interface Step {
18	  op: string;
19	  items?: Item[];
20	}
21	
22	interface Scenario {
23	  customer: { yearsWithMHPCO: number };
24	  steps: Step[];
25	}
26	
27	const BLOCK_SIZE = 3;
28	const BLOCK_PREMIUM = 60;
29	const COMPONENT_TYPES = new Set(["rune"]);
30	
31	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
32	
33	const sumBase = (items: Item[]): number =>
34	  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
35	
36	const priceComponents = (components: Item[]): number =>
37	  components.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumBase(components);
38	
39	const sumBasePremiums = (items: Item[]): number =>
40	  sumBase(items.filter((item) => !isComponent(item))) +
41	  priceComponents(items.filter(isComponent));
42	
43	const applyFirstInsuranceSurcharge = (base: number): number =>
44	  Math.ceil((base * (PERCENT_BASE + FIRST_INSURANCE_PERCENT)) / PERCENT_BASE);
45	
46	const quotePremium = (items: Item[]): number =>
47	  applyFirstInsuranceSurcharge(sumBasePremiums(items)) + PROCESSING_FEE;
48	
49	const executeStep = (step: Step): { premium: number } => ({
50	  premium: quotePremium(step.items ?? []),
51	});
52	
53	export const runScenario = (input: unknown): { results: unknown[] } => {
54	  const scenario = input as Scenario;
55	  return { results: scenario.steps.map(executeStep) };
56	};
